INSERT INTO users (id, phone, email, full_name, role, bio, avatar_url, is_verified, is_active, xp, level, languages, password_hash) VALUES
('00000000-0000-0000-0000-000000000001', '+84901000000', 'admin@huetravel.vn', 'Admin Huế Travel', 'admin', 'Quản trị hệ thống Huế Travel', NULL, true, true, 9999, 'Admin', ARRAY['vi','en'], '$2y$10$ZYHSdrIkmkz64nDIAJSHlu7NyhsC41eqVaxd4ViSmOWRO835nx4Ga'),
('a1111111-1111-1111-1111-111111111111', '+84900001111', 'minh.nguyen@hue.vn', 'Nguyễn Văn Minh', 'guide', 'Hướng dẫn viên 10 năm kinh nghiệm. Tốt nghiệp khoa Lịch sử, ĐH Khoa học Huế. Chuyên tour di sản văn hóa: Đại Nội, lăng tẩm, chùa chiền. Nói tiếng Anh, Pháp.', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=200', true, true, 2500, 'Bậc thầy', ARRAY['vi','en','fr'], '$2y$10$ZYHSdrIkmkz64nDIAJSHlu7NyhsC41eqVaxd4ViSmOWRO835nx4Ga'),
('a2222222-2222-2222-2222-222222222222', '+84900002222', 'lan.tran@hue.vn', 'Trần Thị Lan', 'guide', 'Foodie chính hiệu, 8 năm dẫn food tour Huế. Sinh ra tại Huế, biết rõ mọi ngóc ngách ẩm thực cố đô. Nói tiếng Anh, Hàn Quốc.', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=200', true, true, 1800, 'Chuyên gia', ARRAY['vi','en','ko'], '$2y$10$ZYHSdrIkmkz64nDIAJSHlu7NyhsC41eqVaxd4ViSmOWRO835nx4Ga'),
('a3333333-3333-3333-3333-333333333333', '+84900003333', 'hoa.le@hue.vn', 'Lê Hương Hoa', 'guide', 'Yêu thiên nhiên, 5 năm kinh nghiệm trekking và kayak. Chuyên sinh thái sông Hương, VQG Bạch Mã, và đạp xe làng quê Huế.', 'https://images.unsplash.com/photo-1494790108755-2616b612b786?w=200', true, true, 1200, 'Chuyên gia', ARRAY['vi','en'], '$2y$10$ZYHSdrIkmkz64nDIAJSHlu7NyhsC41eqVaxd4ViSmOWRO835nx4Ga'),
('a4444444-4444-4444-4444-444444444444', '+84900004444', 'dung.hoang@hue.vn', 'Hoàng Dũng', 'guide', '12 năm kinh nghiệm, chuyên Nhã nhạc cung đình và nghệ thuật truyền thống Huế. Biết về thơ ca, tuồng, ca Huế. Nói tiếng Nhật.', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=200', true, true, 3200, 'Bậc thầy', ARRAY['vi','en','ja'], '$2y$10$ZYHSdrIkmkz64nDIAJSHlu7NyhsC41eqVaxd4ViSmOWRO835nx4Ga'),
('b1111111-1111-1111-1111-111111111111', '+84934567890', 'linh.pham@gmail.com', 'Phạm Linh Chi', 'traveler', 'Foodie Sài Gòn, yêu di sản và ẩm thực Huế. Đã đến Huế 4 lần, lần nào cũng khám phá thêm quán mới.', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?w=200', false, true, 650, 'Khám phá', ARRAY['vi'], '$2y$10$ZYHSdrIkmkz64nDIAJSHlu7NyhsC41eqVaxd4ViSmOWRO835nx4Ga'),
('b2222222-2222-2222-2222-222222222222', '+84945678901', 'tuan.hoang@gmail.com', 'Hoàng Minh Tuấn', 'traveler', 'Kỹ sư IT Hà Nội. Thích chụp ảnh phong cảnh, mê lịch sử triều Nguyễn.', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=200', false, true, 280, 'Khám phá', ARRAY['vi','en'], '$2y$10$ZYHSdrIkmkz64nDIAJSHlu7NyhsC41eqVaxd4ViSmOWRO835nx4Ga'),
('b3333333-3333-3333-3333-333333333333', '+84956789012', 'mai.nguyen@gmail.com', 'Nguyễn Thị Mai', 'traveler', 'Travel blogger, yêu chụp ảnh và khám phá văn hóa. 50K followers trên Instagram.', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=200', false, true, 920, 'Khám phá', ARRAY['vi','en'], '$2y$10$ZYHSdrIkmkz64nDIAJSHlu7NyhsC41eqVaxd4ViSmOWRO835nx4Ga');
