('a1111111-1111-1111-1111-111111111111', ARRAY['Di sản văn hóa','Kiến trúc cung đình','Lịch sử triều Nguyễn','Phật giáo Huế'], 10, 4.90, 423, 856, true, true, 'gold', 15, 97.5),
('a2222222-2222-2222-2222-222222222222', ARRAY['Ẩm thực đường phố','Food tour','Nấu ăn cung đình','Chợ truyền thống'], 8, 4.85, 312, 580, true, true, 'gold', 20, 95.0),
('a3333333-3333-3333-3333-333333333333', ARRAY['Sinh thái','Trekking','Kayak','Đạp xe','Sông Hương'], 5, 4.72, 178, 312, true, true, 'silver', 30, 92.0),
('a4444444-4444-4444-4444-444444444444', ARRAY['Nhã nhạc cung đình','Nghệ thuật truyền thống','Văn hóa phi vật thể','Thơ ca Huế'], 12, 4.95, 687, 1245, true, true, 'platinum', 10, 99.0);
INSERT INTO places (name, name_en, slug, description, category, lat, lng, address, image_urls, tags, rating, rating_count) VALUES
('Đại Nội Huế', 'Hue Imperial Citadel', 'dai-noi-hue', 'Kinh thành Huế — Di sản văn hóa thế giới UNESCO. Quần thể cung điện rộng 520 ha, bao gồm Hoàng Thành, Tử Cấm Thành và nhiều công trình kiến trúc độc đáo của triều Nguyễn.', 'sightseeing', 16.4698, 107.5789, '141 Đặng Trần Côn, Thuận Thành, TP Huế', ARRAY['https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800'], ARRAY['di sản','UNESCO','cung đình','triều Nguyễn'], 4.80, 3256),
('Chùa Thiên Mụ', 'Thien Mu Pagoda', 'chua-thien-mu', 'Ngôi chùa cổ 400 năm bên bờ sông Hương, tháp Phước Duyên 7 tầng — biểu tượng tinh thần của cố đô Huế. Được xây dựng năm 1601 dưới thời chúa Nguyễn Hoàng.', 'sightseeing', 16.4539, 107.5532, 'Hà Khê, Kim Long, TP Huế', ARRAY['https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800'], ARRAY['chùa','sông Hương','tháp','tâm linh'], 4.70, 2890),
('Lăng Khải Định', 'Khai Dinh Tomb', 'lang-khai-dinh', 'Lăng tẩm kiến trúc Đông-Tây kết hợp độc đáo nhất Huế. Nổi tiếng với mosaic thủy tinh và sứ vỡ tinh xảo bên trong điện Khải Thành.', 'sightseeing', 16.4107, 107.5798, 'Khải Định, Thủy Bằng, Hương Thủy', ARRAY['https://images.unsplash.com/photo-1571536802807-30451e3955d8?w=800'], ARRAY['lăng tẩm','kiến trúc','triều Nguyễn'], 4.85, 1678),
('Lăng Tự Đức', 'Tu Duc Tomb', 'lang-tu-duc', 'Lăng mộ thơ mộng nhất trong hệ thống lăng tẩm Huế. Hồ Lưu Khiêm với hoa súng, nhà Xung Khiêm Tạ — nơi vua làm thơ và câu cá.', 'sightseeing', 16.4582, 107.5619, 'Thủy Xuân, TP Huế', ARRAY['https://images.unsplash.com/photo-1583418855671-88c9c87efcf9?w=800'], ARRAY['lăng tẩm','vườn','thi ca'], 4.75, 1456),
('Lăng Minh Mạng', 'Minh Mang Tomb', 'lang-minh-mang', 'Lăng tẩm hài hòa nhất về phong thủy. Cầu Trung Đạo, hồ Trừng Minh, Minh Lâu đối xứng hoàn hảo — tuyệt tác kiến trúc phong thủy.', 'sightseeing', 16.4470, 107.5450, 'Hương Thọ, TP Huế', ARRAY['https://images.unsplash.com/photo-1571536802807-30451e3955d8?w=800'], ARRAY['lăng tẩm','phong thủy','kiến trúc'], 4.78, 1234),
('Cầu Trường Tiền', 'Truong Tien Bridge', 'cau-truong-tien', 'Biểu tượng lãng mạn của Huế. 6 nhịp cầu đèn LED đổi màu đẹp lung linh về đêm, nối phố cổ với trung tâm thành phố, bắc qua sông Hương.', 'sightseeing', 16.4650, 107.5870, 'Trường Tiền, Phú Hội, TP Huế', ARRAY['https://images.unsplash.com/photo-1583418855671-88c9c87efcf9?w=800'], ARRAY['cầu','biểu tượng','đêm','sông Hương'], 4.80, 4200),
('Chợ Đông Ba', 'Dong Ba Market', 'cho-dong-ba', 'Chợ truyền thống lớn nhất Huế, thiên đường ẩm thực và mua sắm. Nổi tiếng với bánh bèo, nem lụi, mè xửng, nón bài thơ.', 'food', 16.4697, 107.5927, 'Trần Hưng Đạo, Phú Hòa, TP Huế', ARRAY['https://images.unsplash.com/photo-1555126634-323283e090fa?w=800'], ARRAY['chợ','ẩm thực','mua sắm','street food'], 4.50, 2543),
('Bún Bò Bà Tuyết', 'Ba Tuyet Bun Bo', 'bun-bo-ba-tuyet', 'Quán bún bò nổi tiếng nhất Huế, hoạt động hơn 30 năm. Nước dùng đậm đà, sợi bún to, giò heo mềm. Mở từ 5h sáng, hết hàng trước trưa.', 'food', 16.4645, 107.5875, '47 Phạm Hồng Thái, Phú Hội, TP Huế', ARRAY['https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=800'], ARRAY['bún bò','ẩm thực','nổi tiếng'], 4.60, 1890),
('Đồi Vọng Cảnh', 'Vong Canh Hill', 'doi-vong-canh', 'Ngắm toàn cảnh sông Hương và thành phố Huế từ trên cao. Điểm check-in hoàng hôn tuyệt đẹp, không gian yên bình giữa rừng thông.', 'sightseeing', 16.4380, 107.5670, 'Thủy Biều, TP Huế', ARRAY['https://images.unsplash.com/photo-1472745433479-4556f22e32c2?w=800'], ARRAY['đồi','view','sông Hương','hoàng hôn'], 4.70, 1456),
('Biển Thuận An', 'Thuan An Beach', 'bien-thuan-an', 'Bãi biển gần Huế nhất (15km). Cát trắng, nước trong, hải sản tươi sống. Lý tưởng cho hoàng hôn và seafood đêm.', 'sightseeing', 16.5580, 107.6350, 'Thuận An, Phú Vang, TT-Huế', ARRAY['https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800'], ARRAY['biển','hoàng hôn','hải sản'], 4.40, 987),
('Nhà Vườn Kim Long', 'Kim Long Garden Houses', 'nha-vuon-kim-long', 'Khu nhà vườn truyền thống Huế, không gian yên bình với kiến trúc nhà rường cổ, vườn cây xanh mát. Nơi trải nghiệm văn hóa sống chậm.', 'sightseeing', 16.4555, 107.5695, 'Kim Long, TP Huế', ARRAY['https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=800'], ARRAY['nhà vườn','truyền thống','văn hóa'], 4.65, 678),
('Phố Đi Bộ Nguyễn Đình Chiểu', 'Nguyen Dinh Chieu Walking Street', 'pho-di-bo-nguyen-dinh-chieu', 'Con phố sống động nhất Huế về đêm. Ẩm thực đường phố, quán cà phê, âm nhạc live, bán đồ handmade.', 'sightseeing', 16.4620, 107.5890, 'Nguyễn Đình Chiểu, TP Huế', ARRAY['https://images.unsplash.com/photo-1555126634-323283e090fa?w=800'], ARRAY['phố đi bộ','đêm','ẩm thực','nightlife'], 4.55, 1876);
INSERT INTO experiences (id, guide_id, title, slug, description, category, duration_mins, price, max_guests, meeting_point, meeting_lat, meeting_lng, image_urls, highlights, includes, is_active, is_instant, rating, rating_count) VALUES
('d1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111111', 'Khám phá Đại Nội Huế — Di sản UNESCO', 'kham-pha-dai-noi-hue', 'Chuyến tham quan Đại Nội Huế kéo dài 3 giờ. Bước qua Ngọ Môn, chiêm ngưỡng Điện Thái Hòa — nơi làm lễ đăng quang của 13 vị vua Nguyễn. Khám phá Tử Cấm Thành bí ẩn và Thế Miếu uy nghiêm.', 'sightseeing', 180, 350000, 8, 'Cổng Ngọ Môn, Đại Nội Huế', 16.4698, 107.5789, ARRAY['https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800','https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800'], ARRAY['Ngọ Môn','Điện Thái Hòa','Tử Cấm Thành','Thế Miếu','Hiển Lâm Các'], ARRAY['Vé vào cổng','Hướng dẫn viên','Nước uống','Nón lá'], true, true, 4.90, 423),
('d2222222-2222-2222-2222-222222222222', 'a1111111-1111-1111-1111-111111111111', 'Tour Lăng Tẩm Hoàng Gia — Khải Định & Tự Đức', 'tour-lang-tam-hoang-gia', 'Tham quan hai lăng tẩm đẹp nhất Huế: Lăng Khải Định với kiến trúc Đông-Tây kết hợp, mosaic tinh xảo. Và Lăng Tự Đức thơ mộng bên hồ Lưu Khiêm — nơi vua làm thơ và câu cá.', 'sightseeing', 240, 500000, 6, 'Lăng Khải Định, Huế', 16.4107, 107.5798, ARRAY['https://images.unsplash.com/photo-1571536802807-30451e3955d8?w=800'], ARRAY['Lăng Khải Định','Lăng Tự Đức','Hồ Lưu Khiêm','Kiến trúc cung đình'], ARRAY['Vé tham quan','Hướng dẫn viên','Xe đưa đón','Nước uống'], true, false, 4.85, 312),
('d3333333-3333-3333-3333-333333333333', 'a2222222-2222-2222-2222-222222222222', 'Food Tour Ẩm Thực Đường Phố Huế', 'food-tour-am-thuc-duong-pho-hue', '4 giờ khám phá 8 món ăn đặc sắc nhất Huế: bún bò Bà Tuyết, cơm hến đường Chi Lăng, bánh bèo/nậm/lọc Huyền Anh, chè Huế hẻm Hùng Vương, nem lụi chợ Đông Ba.', 'food', 240, 400000, 6, 'Chợ Đông Ba, Huế', 16.4697, 107.5927, ARRAY['https://images.unsplash.com/photo-1555126634-323283e090fa?w=800','https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=800'], ARRAY['Bún bò Huế','Cơm hến','Bánh bèo/nậm/lọc','Chè Huế','Nem lụi'], ARRAY['8 món ăn','Hướng dẫn viên','Nước uống','Bảo hiểm'], true, true, 4.92, 580),
('d4444444-4444-4444-4444-444444444444', 'a2222222-2222-2222-2222-222222222222', 'Workshop Nấu Ăn Cung Đình Huế', 'workshop-nau-an-cung-dinh', 'Học nấu 3 món ẩm thực cung đình: bánh bèo chén, nem công chúa, chè hạt sen long nhãn. Bắt đầu bằng đi chợ truyền thống, nấu bếp trong nhà vườn truyền thống.', 'food', 300, 600000, 4, 'Nhà vườn Kim Long, Huế', 16.4555, 107.5695, ARRAY['https://images.unsplash.com/photo-1556910103-1c02745aae4d?w=800'], ARRAY['Chợ truyền thống','Học nấu ăn','Ẩm thực cung đình','Thưởng thức'], ARRAY['Nguyên liệu','Chef hướng dẫn','Tạp dề','Công thức'], true, false, 4.78, 178),
('d5555555-5555-5555-5555-555555555555', 'a3333333-3333-3333-3333-333333333333', 'Sunset Kayak Sông Hương', 'sunset-kayak-song-huong', 'Chèo kayak sông Hương lúc hoàng hôn. Xuất phát từ bến thuyền Tòa Khâm, ngắm Cầu Trường Tiền đổi màu LED, Chùa Thiên Mụ lung linh trong ánh chiều tà.', 'experience', 150, 280000, 8, 'Bến thuyền Tòa Khâm, Huế', 16.4620, 107.5850, ARRAY['https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800','https://images.unsplash.com/photo-1472745433479-4556f22e32c2?w=800'], ARRAY['Kayak sông Hương','Hoàng hôn','Cầu Trường Tiền','Chùa Thiên Mụ'], ARRAY['Kayak + áo phao','Hướng dẫn viên','Nước uống','Ảnh chụp'], true, true, 4.82, 245),
('d6666666-6666-6666-6666-666666666666', 'a3333333-3333-3333-3333-333333333333', 'Trekking Vườn Quốc Gia Bạch Mã', 'trekking-bach-ma', 'Một ngày trekking VQG Bạch Mã — đỉnh núi 1450m, thác Đỗ Quyên hùng vĩ, view biển Thừa Thiên từ trên cao. Khí hậu mát mẻ quanh năm.', 'experience', 480, 750000, 6, 'Cổng VQG Bạch Mã', 16.2020, 107.8543, ARRAY['https://images.unsplash.com/photo-1551632811-561732d1e306?w=800'], ARRAY['Jungle trekking','Thác Đỗ Quyên','Đỉnh 1450m','View biển'], ARRAY['Hướng dẫn viên','Vé vào cổng','Bữa trưa','Nước uống','Bảo hiểm'], true, false, 4.68, 134),
('d7777777-7777-7777-7777-777777777777', 'a4444444-4444-4444-4444-444444444444', 'Đêm Nhạc Cung Đình trên Sông Hương', 'dem-nhac-cung-dinh-song-huong', 'Thưởng thức Nhã nhạc UNESCO trên thuyền Rồng lướt sông Hương. Biểu diễn nhạc cụ cung đình sống, uống trà sen Tịnh Tâm, ăn bánh Huế.', 'experience', 120, 450000, 12, 'Bến Thuyền Rồng, Lê Lợi', 16.4612, 107.5869, ARRAY['https://images.unsplash.com/photo-1514320291840-2e0a9bf2a9ae?w=800'], ARRAY['Nhã nhạc UNESCO','Thuyền Rồng','Trà cung đình','Biểu diễn sống'], ARRAY['Vé thuyền','Biểu diễn','Trà + bánh','Audio guide'], true, true, 4.95, 687),
('d8888888-8888-8888-8888-888888888888', 'a2222222-2222-2222-2222-222222222222', 'Đạp Xe Làng Cổ Phước Tích', 'dap-xe-lang-co-phuoc-tich', 'Đạp xe 20km khám phá làng cổ 500 tuổi Phước Tích — nhà rường cổ, nghề gốm truyền thống 500 năm. Di tích Quốc gia đặc biệt.', 'tour', 300, 350000, 8, 'Làng cổ Phước Tích, Phong Điền', 16.5800, 107.3400, ARRAY['https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=800'], ARRAY['Làng cổ 500 tuổi','Nhà rường','Nghề gốm','Ẩm thực làng'], ARRAY['Xe đạp + mũ','Hướng dẫn viên','Bữa trưa','Nước uống'], true, false, 4.75, 198),
('d9999999-9999-9999-9999-999999999999', 'a1111111-1111-1111-1111-111111111111', 'Tour Hoàng Hôn Sông Hương — Xe Đạp & Thuyền', 'tour-hoang-hon-song-huong', 'Đạp xe bờ Bắc sông Hương qua Chùa Thiên Mụ, nhà vườn Kim Long. Sau đó lên thuyền ngắm hoàng hôn, qua Cầu Trường Tiền lung linh.', 'tour', 210, 320000, 6, 'Nhà vườn Kim Long', 16.4555, 107.5695, ARRAY['https://images.unsplash.com/photo-1472745433479-4556f22e32c2?w=800'], ARRAY['Đạp xe bờ Bắc','Chùa Thiên Mụ','Hoàng hôn thuyền','Cầu Trường Tiền'], ARRAY['Xe đạp','Thuyền','Hướng dẫn viên','Trà + bánh Huế'], true, true, 4.88, 167),
('da101010-1010-1010-1010-101010101010', 'a4444444-4444-4444-4444-444444444444', 'Trải Nghiệm Áo Dài & Chụp Ảnh Đại Nội', 'trai-nghiem-ao-dai-chup-anh', 'Mặc áo dài cung đình, chụp ảnh tại các điểm iconic trong Đại Nội: Ngọ Môn, Điện Thái Hòa, Tử Cấm Thành. Nhiếp ảnh gia chuyên nghiệp.', 'experience', 150, 500000, 4, 'Cổng Ngọ Môn, Đại Nội', 16.4698, 107.5789, ARRAY['https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800'], ARRAY['Áo dài cung đình','Chụp ảnh chuyên nghiệp','Đại Nội','Makeup'], ARRAY['Áo dài','Nhiếp ảnh gia','Vé Đại Nội','30 ảnh edited'], true, true, 4.91, 234);
