INSERT INTO reviews (booking_id, traveler_id, experience_id, overall_rating, guide_rating, value_rating, comment, is_featured) VALUES
('e1111111-1111-1111-1111-111111111111', 'b1111111-1111-1111-1111-111111111111', 'd3333333-3333-3333-3333-333333333333', 5.0, 5.0, 4.5, 'Tuyệt vời! Chị Lan rất nhiệt tình, dẫn đi ăn 8 quán local mà chỉ người Huế mới biết. Bún bò Bà Tuyết và chè Huế hẻm là top 1! Sẽ đăng ký food tour lại lần tới.', true),
('e2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222222', 'd1111111-1111-1111-1111-111111111111', 4.5, 5.0, 4.0, 'Anh Minh kể chuyện lịch sử rất hấp dẫn! Những câu chuyện về Tử Cấm Thành mà sách không ghi, về vua Thành Thái và cuộc cách mạng... Đáng đồng tiền bát gạo!', true),
('e4444444-4444-4444-4444-444444444444', 'b1111111-1111-1111-1111-111111111111', 'd5555555-5555-5555-5555-555555555555', 4.5, 4.5, 5.0, 'Chèo kayak sông Hương lúc hoàng hôn đẹp tuyệt vời! Cầu Trường Tiền lung linh, Chùa Thiên Mụ huyền bí. Giá cả hợp lý, đề xuất 100%!', false),
('e6666666-6666-6666-6666-666666666666', 'b3333333-3333-3333-3333-333333333333', 'da101010-1010-1010-1010-101010101010', 5.0, 5.0, 5.0, 'Trải nghiệm mặc áo dài chụp ảnh trong Đại Nội tuyệt vời! Nhiếp ảnh gia rất chuyên nghiệp, biết đúng góc đẹp. 30 ảnh nhận được đều lung linh. Must try!', true);
INSERT INTO blog_posts (author_id, slug, title, excerpt, cover_image, content, tags, category, view_count, like_count, is_published, is_featured, published_at) VALUES
('a1111111-1111-1111-1111-111111111111', 'top-10-diem-check-in-dep-nhat-hue-2026', 'Top 10 Điểm Check-in Đẹp Nhất Huế 2026', 'Khám phá 10 điểm check-in đẹp nhất cố đô Huế, từ Đại Nội đến đồi Vọng Cảnh.', 'https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800', E'# Top 10 Điểm Check-in Đẹp Nhất Huế 2026\n\n## 1. Đại Nội\nKinh thành Huế, hoàng hôn tại Ngọ Môn là thời điểm đẹp nhất.\n\n## 2. Cầu Trường Tiền\nIcon của Huế, lung linh nhất vào buổi đêm với đèn LED đổi màu.\n\n## 3. Chùa Thiên Mụ\nNgôi chùa cổ 400 năm bên bờ sông Hương.\n\n## 4. Lăng Khải Định\nKiến trúc Đông-Tây kết hợp, mosaic tinh xảo.\n\n## 5. Đồi Vọng Cảnh\nNgắm toàn cảnh sông Hương từ trên cao.', ARRAY['check-in','huế','du lịch'], 'tips', 3250, 187, true, true, '2026-03-01 10:00:00+07'),
('a2222222-2222-2222-2222-222222222222', 'huong-dan-an-sap-hue-trong-24-gio', 'Hướng Dẫn Ăn Sập Huế Trong 24 Giờ', 'Lịch trình ăn uống chi tiết từ sáng đến tối, đảm bảo no đến tận cổ.', 'https://images.unsplash.com/photo-1555126634-323283e090fa?w=800', E'# Ăn Sập Huế Trong 24 Giờ 🍜\n\n## Sáng (6:00-8:00)\n- **Bún bò Huế** tại quán Bà Tuyết, 47 Phạm Hồng Thái\n- **Bánh canh cua** gần chợ An Cựu\n\n## Giữa sáng\n- **Bánh bèo, nậm, lọc** tại Huyền Anh\n- **Chè Huế** thập cẩm hẻm Hùng Vương\n\n## Trưa\n- **Cơm hến** Bà Mai, đường Chi Lăng\n\n## Chiều\n- **Nem lụi** cuốn bánh tráng tại chợ Đông Ba\n\n## Tối\n- **Ốc Huế** — ốc xào me, ốc nướng mỡ hành\n\n> 💡 Budget: ~300,000-500,000đ cho cả ngày!', ARRAY['ẩm thực','bún bò','street food'], 'food', 5340, 356, true, true, '2026-02-15 09:00:00+07'),
('a3333333-3333-3333-3333-333333333333', 'cam-nang-du-lich-hue-mua-he-2026', 'Cẩm Nang Du Lịch Huế Mùa Hè 2026', 'Tất cả những gì bạn cần biết để có chuyến đi Huế mùa hè hoàn hảo.', 'https://images.unsplash.com/photo-1583418855671-88c9c87efcf9?w=800', E'# Cẩm Nang Du Lịch Huế Mùa Hè 2026 ☀️\n\n## Thời tiết\nMùa hè Huế nóng (32-38°C). Đi sáng sớm hoặc chiều mát.\n\n## Lịch trình 3N2Đ\n### Ngày 1: Di sản\nĐại Nội → Lăng Khải Định → Thuyền Rồng\n\n### Ngày 2: Ẩm thực\nFood tour → Chùa Thiên Mụ → Kayak sông Hương\n\n### Ngày 3: Thiên nhiên\nBiển Thuận An → Làng hương Thủy Xuân\n\n## Chi phí: ~3,600,000đ/người', ARRAY['cẩm nang','mùa hè','budget'], 'guide', 2890, 142, true, false, '2026-03-10 08:00:00+07'),
('a4444444-4444-4444-4444-444444444444', 'nha-nhac-cung-dinh-hue-di-san-phi-vat-the', 'Nhã Nhạc Cung Đình Huế — Di Sản Phi Vật Thể UNESCO', 'Tìm hiểu về Nhã nhạc — âm nhạc cung đình được UNESCO công nhận.', 'https://images.unsplash.com/photo-1514320291840-2e0a9bf2a9ae?w=800', E'# Nhã Nhạc Cung Đình Huế\n\nNhã nhạc là loại hình âm nhạc cung đình Việt Nam, được UNESCO công nhận là Di sản Văn hóa Phi vật thể năm 2003.\n\n## Lịch sử\nHình thành từ thế kỷ 15, phát triển rực rỡ dưới triều Nguyễn.\n\n## Nhạc cụ\nĐàn nguyệt, đàn tranh, sáo trúc, trống...\n\n## Trải nghiệm\nBạn có thể thưởng thức Nhã nhạc trên thuyền Rồng sông Hương.', ARRAY['nhã nhạc','UNESCO','văn hóa'], 'culture', 1560, 98, true, false, '2026-03-05 14:00:00+07');
INSERT INTO local_events (title, description, category, location_name, lat, lng, cover_image, organizer, is_free, price, starts_at, ends_at) VALUES
('Festival Huế 2026', 'Lễ hội Festival Huế — Di sản văn hóa, âm nhạc, nghệ thuật đường phố, trình diễn áo dài, ẩm thực. Sự kiện lớn nhất Huế 2 năm 1 lần.', 'festival', 'Đại Nội Huế', 16.4698, 107.5789, 'https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800', 'UBND tỉnh Thừa Thiên Huế', true, 0, NOW() + INTERVAL '30 days', NOW() + INTERVAL '37 days'),
('Chợ Đêm Phố Cổ Bao Vinh', 'Chợ đêm ẩm thực và thủ công mỹ nghệ tại phố cổ Bao Vinh. Hơn 50 gian hàng đặc sản Huế.', 'market', 'Phố cổ Bao Vinh', 16.4780, 107.5920, NULL, 'Phường Bao Vinh', true, 0, NOW() + INTERVAL '4 days', NOW() + INTERVAL '4 days' + INTERVAL '6 hours'),
('Đêm Nhạc Jazz Sông Hương', 'Biểu diễn nhạc Jazz trên thuyền Rồng. Nghệ sĩ Việt Nam và quốc tế biểu diễn sống.', 'concert', 'Bến thuyền Tòa Khâm', 16.4620, 107.5850, NULL, 'Huế Music Club', false, 200000, NOW() + INTERVAL '9 days', NOW() + INTERVAL '9 days' + INTERVAL '3 hours'),
('Triển Lãm Mỹ Thuật Huế', 'Triển lãm tranh và điêu khắc nghệ nhân Huế. 50+ tác phẩm đương đại và truyền thống.', 'exhibition', 'Trung tâm Nghệ thuật Lê Bá Đảng', 16.4650, 107.5800, NULL, 'Hội Mỹ thuật Huế', true, 0, NOW() + INTERVAL '15 days', NOW() + INTERVAL '45 days'),
('Workshop Làm Bánh Huế', 'Học làm bánh lọc, bánh nậm, bánh bèo từ nghệ nhân làng. Trải nghiệm ẩm thực truyền thống.', 'workshop', 'Nhà vườn Kim Long', 16.4550, 107.5700, NULL, 'Hội Nấu ăn Huế', false, 150000, NOW() + INTERVAL '6 days', NOW() + INTERVAL '6 days' + INTERVAL '3 hours'),
('Giải Chạy Marathon Huế 2026', 'Marathon quốc tế chạy dọc sông Hương và qua các di tích Huế. Cự ly 5K, 10K, 21K, 42K.', 'sport', 'Cầu Trường Tiền', 16.4650, 107.5870, NULL, 'Sở VHTT TT-Huế', false, 300000, NOW() + INTERVAL '60 days', NOW() + INTERVAL '60 days' + INTERVAL '7 hours');
