('b3333333-3333-3333-3333-333333333333', 'Lần đầu nghe Nhã nhạc cung đình trên thuyền Rồng 🎶🚣 Cảm giác như quay về thời Nguyễn #nhanhachu #unesco', ARRAY['https://images.unsplash.com/photo-1514320291840-2e0a9bf2a9ae?w=800'], 'image', 'Sông Hương, Huế', 16.4612, 107.5869, 89, 15),
('b1111111-1111-1111-1111-111111111111', 'Trekking Bạch Mã mệt nhưng đáng, thác Đỗ Quyên hùng vĩ quá! 🌿⛰️ #bachma #trekking', ARRAY['https://images.unsplash.com/photo-1551632811-561732d1e306?w=800'], 'image', 'VQG Bạch Mã', 16.2020, 107.8543, 34, 5),
('b3333333-3333-3333-3333-333333333333', 'Mặc áo dài chụp ảnh Đại Nội sáng nay, nhiếp ảnh gia quá pro! 📸✨ Ảnh nào cũng đẹp #aodai #dainoi', ARRAY['https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800'], 'image', 'Đại Nội Huế', 16.4698, 107.5789, 112, 23);
